-- Insert program sections for Acharya (College)
INSERT INTO program_sections (program_id, section_key, title, content) VALUES
((SELECT id FROM programs WHERE slug = 'acharya'), 'header', 'From Campus Conversations to Corporate Confidence', 'Great careers begin with clear communication. At Acharya Institute, Bangalore, the gap between technical skills and professional readiness was evident among students preparing for the job market. Recognizing this, Rareminds was brought in to bridge the communication gap and empower students with the skills they need to thrive in the real world.'),
((SELECT id FROM programs WHERE slug = 'acharya'), 'introduction', 'Introduction', 'In May 2022–2023, Rareminds conducted a high-impact 5-day Business Communication course for over 700 students across the Physiotherapy, MBA, and MCA departments. The sessions were tailored to enhance industry-specific communication, presentation skills, and professional behavior. This was followed by pre-placement readiness training for 120 MBA and 233 MCA students in 2024, building confidence right before they stepped into the hiring ecosystem.'),
((SELECT id FROM programs WHERE slug = 'acharya'), 'modules', 'Modules Covered', 'Industry-Oriented Communication Frameworks. Email and Business Writing Best Practices. Presentation and Interview Skills. Group Discussions and Personal Branding. Corporate Etiquette and Workplace Readiness.'),
((SELECT id FROM programs WHERE slug = 'acharya'), 'approaches', 'Multiple Approaches', 'Interactive Simulations & Mock Interviews. Real-time Feedback Loops. Resume Labs and Elevator Pitch Practice. Peer Critique Sessions.'),
((SELECT id FROM programs WHERE slug = 'acharya'), 'impact', 'Outcomes and Impact', '85% of students reported increased clarity and confidence in job interviews. Campus recruiters highlighted better articulation and professionalism in placement rounds. MBA & MCA placement coordinators reported smoother pre-placement processes.'),
((SELECT id FROM programs WHERE slug = 'acharya'), 'strategic_alignment', 'Strategic Alignment with Acharya''s Vision', 'This initiative aligned seamlessly with Acharya Institute''s goals of: Enhancing Industry Readiness Among Graduates. Elevating Communication as a Core Career Skill. Enabling Seamless Transition from Classroom to Corporate. Strengthening Placement Outcomes through Holistic Training.'),
((SELECT id FROM programs WHERE slug = 'acharya'), 'video', 'Program Videos', '[{"item1":"/video1.mp4","item2":"/video2.mp4","item3":"/video3.mp4"}]'),
((SELECT id FROM programs WHERE slug = 'acharya'), 'conclusion', 'Crafting Communicators, Not Just Candidates', 'At Acharya Institute, Rareminds went beyond basic communication training. We helped students shape their voice, articulate their value, and enter the professional world with poise and purpose. The impact was clear: sharper skills, stronger confidence, and a generation ready to make their mark.')
ON CONFLICT (program_id, section_key) DO NOTHING;
-- Insert program sections for PES (College)
INSERT INTO program_sections (program_id, section_key, title, content) VALUES
((SELECT id FROM programs WHERE slug = 'pes'), 'introduction', 'Introduction', 'The Rareminds Bootcamp at PES Engineering College, Mandya, contributed to transform aspiring engineers into confident, industry-ready developers. Through an intensive, 45-hour Web Development Bootcamp, we bridged the classroom-to-career gap with a hands-on, real-world coding experience that left students skilled, motivated, and ready for the digital future.'),
((SELECT id FROM programs WHERE slug = 'pes'), 'about', 'About the Program', 'Web Development Bootcamp: From July 24th to 29th, 2023, Rareminds delivered a comprehensive Web Development Bootcamp focused on Full Stack skills. The program immersed students in practical learning, from HTML, CSS, and JavaScript to React, backend integration, APIs, and deployment techniques.

Learning Approach: Designed around active problem-solving, teamwork, and real-time feedback, this initiative gave students the tools to think like developers and build like professionals.'),
((SELECT id FROM programs WHERE slug = 'pes'), 'impact', 'Key Outcomes & Impact', 'Trained 100+ students through immersive bootcamp sessions combining technical depth and collaborative learning. 70% of students built fully functional web applications from scratch. 90% actively participated in hands-on coding exercises and real-time problem-solving. 100% expressed confidence in building, securing, and deploying full-stack web applications. 85% reported improved critical thinking and collaboration skills applicable across technical and non-technical settings. 92% experienced growth in communication and teamwork through pair programming and group challenges. 88% said they could now clearly articulate technical ideas, preparing them for interviews and presentations.'),
((SELECT id FROM programs WHERE slug = 'pes'), 'strategic_alignment', 'Strategic Alignment with PES College Goals', 'This initiative reinforced PES Engineering College''s commitment to: Skill-Based, Industry-Ready Learning. NAAC and NIRF Enhancement through Outcome-Focused Programs. Innovation and Startup Culture among Students. Improved Placement Readiness with Practical Tech Exposure. NEP 2020 Alignment through experiential, future-focused education.'),
((SELECT id FROM programs WHERE slug = 'pes'), 'video', 'Program Videos', '[{"item1":"/video1.mp4","item2":"/video2.mp4","item3":"/video3.mp4"}]'),
((SELECT id FROM programs WHERE slug = 'pes'), 'conclusion', 'Turning Coders into Creators', 'At PES Engineering College, Rareminds didn''t just teach programming — we built a culture of innovation, confidence, and readiness. By empowering students to develop real solutions, communicate effectively, and collaborate as tech professionals, we helped transform the campus into a launchpad for tomorrow''s digital leaders.')
ON CONFLICT (program_id, section_key) DO NOTHING;
-- Insert program sections for VELS (College)
INSERT INTO program_sections (program_id, section_key, title, content) VALUES
((SELECT id FROM programs WHERE slug = 'vels'), 'introduction', 'Introduction', 'Rareminds training programs at VELS University to reshape technical education for first-year students, delivering high-impact, project-based training in emerging technologies. The initiative successfully bridged classroom learning with real-world application, equipping students with future-ready skills and confidence for the evolving digital workplace.'),
((SELECT id FROM programs WHERE slug = 'vels'), 'about', 'About the Program', 'Industrial Metaverse: Two 45-hour experiential training programs were delivered to undergraduate students as part of this collaboration. This program combined cutting-edge tools like VR and AI with hands-on projects, enabling students to simulate real-world environments from day one.

Web Full Stack Development: Two 45-hour experiential training programs were delivered to undergraduate students as part of this collaboration. This program combined the MERN stack with hands-on projects, enabling students to code, build, and deploy real-world applications from day one.'),
((SELECT id FROM programs WHERE slug = 'vels'), 'impact', 'Key Outcomes & Impact', '200+ students trained through structured, mentor-led sessions. 90% of participants built deployable full-stack applications using modern frameworks and platforms. 95% of students rated the training 8/10 or higher for content, delivery, and usefulness. 85% reported improved career confidence, especially in applying skills to internships and interviews. Students demonstrated enhanced critical thinking and teamwork, with active participation in all sessions. Positive institutional feedback from faculty who observed increased engagement, curiosity, and practical understanding.'),
((SELECT id FROM programs WHERE slug = 'vels'), 'strategic_alignment', 'Strategic Alignment with VELS University Goals', 'This initiative supported key institutional objectives such as: NAAC & NIRF enhancement through experiential learning and tech integration. Improved employability outcomes via skill-based, industry-aligned content. Curriculum innovation, aligned with NEP 2020 and industry expectations. Higher student engagement contributes to improved retention and satisfaction.'),
((SELECT id FROM programs WHERE slug = 'vels'), 'video', 'Program Videos', '[{"item1":"/video1.mp4","item2":"/video2.mp4","item3":"/video3.mp4"}]'),
((SELECT id FROM programs WHERE slug = 'vels'), 'conclusion', 'Conclusion', 'This successful collaboration with VELS University demonstrated Rareminds'' ability to deliver measurable outcomes, transform student learning, and align with institutional goals. By turning classrooms into innovation labs, we empowered students to become creators, not just consumers of technology.')
ON CONFLICT (program_id, section_key) DO NOTHING;
-- Insert program sections for DSATM (College)
INSERT INTO program_sections (program_id, section_key, title, content) VALUES
((SELECT id FROM programs WHERE slug = 'dsatm'), 'introduction', 'The Real-World Leap: How DSATM Students Gained a Competitive Edge', 'Rareminds has been a long-standing training partner for DSATM, driving student employability through curated, career-oriented workshops. By integrating both technical and soft skill components, these programs empowered engineering and management students with practical tools to thrive in professional settings.'),
((SELECT id FROM programs WHERE slug = 'dsatm'), 'about', 'About the Program', 'MBA Students: 5-Day Advanced Excel Workshop (Sept–Oct 2019). Focused on business analytics and reporting through practical spreadsheet applications.

Non-Teaching Staff: MS Office & Email Etiquette (Feb 2019) – 3-day session introducing essential digital tools and workplace communication. Advanced Excel, Time Management & Personal Branding via Social Media (July 2019) – A holistic 3-day program to enhance productivity and professional presence.

Civil Engineering Students: Day 1: Surveying & geospatial analysis using Total Station & GIS. Day 2: Construction Project Management tools and methodologies (PERT, CPM, EVM). Day 3: BIM, Risk Management, and digital modeling exposure. Participation: 60 students.'),
((SELECT id FROM programs WHERE slug = 'dsatm'), 'impact', 'Key Outcomes & Impact', '100+ participants trained across engineering, management, and staff categories. Practical exposure to tools like MS Excel, Total Station, and BIM. Positive feedback across sessions for delivery, content relevance, and applicability. Strengthened cross-functional competencies like project planning, digital communication, and personal branding. Programs led by industry experts ensured real-world context and engagement.'),
((SELECT id FROM programs WHERE slug = 'dsatm'), 'strategic_alignment', 'Strategic Alignment with DSATM Goals', 'This engagement supported DSATM''s mission to: Enhance student employability through skill-based learning. Encourage interdisciplinary exposure and industry linkage. Build digital and workplace readiness across academic and administrative stakeholders. Foster a continuous learning culture in both student and staff communities.'),
((SELECT id FROM programs WHERE slug = 'dsatm'), 'video', 'Program Videos', '[{"item1":"/video1.mp4","item2":"/video2.mp4","item3":"/video3.mp4"}]'),
((SELECT id FROM programs WHERE slug = 'dsatm'), 'conclusion', 'Conclusion', 'Rareminds'' collaboration with DSATM highlights how focused, practical training can drive institutional growth, individual confidence, and long-term career success. By delivering real-world learning across multiple touchpoints, this partnership continues to shape a more future-ready, skilled campus ecosystem.')
ON CONFLICT (program_id, section_key) DO NOTHING;
-- Note: Visvesvaraya Technological University has no sections in frontend data, so no program_sections entries are added for it.
-- =====================================================
-- BLDEA PROGRAM SECTIONS
-- =====================================================

-- Insert program sections for BLDEA
INSERT INTO program_sections (program_id, section_key, title, content) VALUES
((SELECT id FROM programs WHERE slug = 'bldea'), 'introduction', 'Elevating Everyday Teaching into Transformational Practice', 'Building great schools begins with investing in great teachers. BLDEA Schools in Karnataka recognized the need to move beyond routine training and focus on structured, high-impact development. Teachers were navigating classrooms without consistent support in pedagogy, communication, emotional intelligence, and NEP-aligned practices. A unified approach was necessary to ensure that professional growth was intact across levels and that the student engagement remained consistent, meaningful, and aligned with evolving learning needs. Rareminds delivered a concentrated, practice-based model focused on both mindset and method. Rareminds conducted a 3-day intensive program for over 200 teachers across the BLDEA network. Sessions were led by 5 master trainers and grounded in real classroom challenges.'),
((SELECT id FROM programs WHERE slug = 'bldea'), 'modules', 'Modules Covered', 'NEP 2020 Alignment and Classroom Planning. Assessment Frameworks and Tools. Inclusive Teaching Practices. Empathy in Education. Positive Engagement and Student Motivation.'),
((SELECT id FROM programs WHERE slug = 'bldea'), 'approaches', 'Multiple Approaches', 'Roleplays and Scenario-Based Problem Solving. Lesson Design Labs. Peer Reflection Circles and Collaborative Planning.'),
((SELECT id FROM programs WHERE slug = 'bldea'), 'impact', 'Outcomes and Impact', '90% of teachers submitted revised lesson plans aligned to new practices. Higher ownership, clarity, and classroom strategy observed across cohorts. School leadership committed to ongoing mentoring circles and internal CPD.'),
((SELECT id FROM programs WHERE slug = 'bldea'), 'strategic_alignment', 'Strategic Alignment with BLDEA Goals', 'This initiative directly supported BLDEA''s commitment to: NEP 2020 Integration in Teaching Practice. Structured Professional Development for Staff. Improved Student Engagement through Active Methodologies. Internal Leadership Capacity through Peer Mentoring Models. Outcome-Based Approaches in Academic Delivery.'),
((SELECT id FROM programs WHERE slug = 'bldea'), 'video', 'Program Videos', '[{"item1":"/video1.mp4","item2":"/video2.mp4","item3":"/video3.mp4"}]'),
((SELECT id FROM programs WHERE slug = 'bldea'), 'conclusion', 'Turning Teachers into Changemakers', 'At BLDEA Schools, Rareminds didn''t just train teachers—we helped shift the culture of classrooms. By building both confidence and capability, our approach enabled teachers to become reflective practitioners who lead learning with clarity, care, and consistency. Together, we laid the foundation for a sustainable teaching excellence model rooted in purpose, pedagogy, and practice.')
ON CONFLICT (program_id, section_key) DO NOTHING;
-- =====================================================
-- NAAN MUDHALVAN CATEGORY PROGRAM SECTIONS
-- =====================================================

-- Insert program sections for Naan Mudhalvan 2024
INSERT INTO program_sections (program_id, section_key, title, content) VALUES
((SELECT id FROM programs WHERE slug = 'naan-mudhalvan-2024'), 'introduction', 'Introduction', 'Rareminds proudly partnered with the Tamil Nadu Skill Development Corporation (TNSDC) under the Naan Mudhalvan flagship initiative to transform technical education for Arts and Science students across Tamil Nadu. This program focused on delivering high-impact, project-based training in critical emerging technologies—bridging classroom theory with real-world practice. The partnership empowered students with future-ready skills, practical exposure, and the confidence to meet the demands of an evolving digital and industrial workforce.'),
((SELECT id FROM programs WHERE slug = 'naan-mudhalvan-2024'), 'about', 'About the Program', 'Through this collaboration, Rareminds delivered four specialized 45-hour experiential training programs to undergraduate students during the Even Semesters of the 2024–2025 academic year. These mandatory programs provided immersive, hands-on learning experiences in the following sectors: Chemical Safety in Battery Management, EV Battery Management Systems, Food Analysis Processing and Preservation, Organic Food Production. Each course blended in-person instruction with LMS-based support, enabling students to work on real-time simulations, hands-on projects, and practical applications from day one. The programs were designed to enhance both technical competencies and employability skills in alignment with industry expectations.'),
((SELECT id FROM programs WHERE slug = 'naan-mudhalvan-2024'), 'course_enrollment', 'Course Enrollment by University', 'Organic Food Practices - Total: 2,312 students across Bharathidasan University (1,056), Manonmaniam Sundranar University (569), Alagappa University (294), Madurai Kamaraj University (276), Mother Teresa University (117). Food Analysis Processing and Preservation - Total: 2,230 students across Periyar University (1,419), Annamalai University (589), Bharathiar University (222). Medical Coding - Total: 3,807 students across Thiruvalluvar University (1,532), Annamalai University (1,416), Madurai Kamaraj University (643), Mother Teresa University (216). Agri Business Management - Total: 2,449 students across Thiruvalluvar University (1,237), University of Madras (1,212).'),
((SELECT id FROM programs WHERE slug = 'naan-mudhalvan-2024'), 'impact', 'Key Outcomes & Impact', '10,798 students were trained through structured, mentor-led sessions across partner universities in Tamil Nadu. All participants successfully completed comprehensive final projects, showcasing the practical application of their learning Evaluations were jointly conducted by college faculty and Rareminds'' industry experts. Where applicable, students actively participated in mandatory hackathons—fostering innovation, critical thinking, and collaborative problem-solving. Employability outcomes were strengthened through integrated support for placements, internships, and real-time project experiences. Institutional feedback from TNSDC and participating universities was overwhelmingly positive, noting higher student engagement, curiosity, and application-based learning.'),
((SELECT id FROM programs WHERE slug = 'naan-mudhalvan-2024'), 'strategic_alignment', 'Strategic Alignment with TNSDC Goals', 'Skill Development & Employability: Delivery of industry-aligned content enhanced the job readiness of Arts and Science graduates.

Curriculum Innovation: Courses introduced students to emerging technologies, aligning academic learning with evolving industry demands.

Student Engagement & Retention: Project-based methodologies significantly improved student interest, satisfaction, and knowledge retention.

Workforce Readiness: The initiative helped create a skilled talent pipeline in critical sectors supporting Tamil Nadu economic and industrial development.'),
((SELECT id FROM programs WHERE slug = 'naan-mudhalvan-2024'), 'video', 'Program Videos',              '[{"item1":"/video1.mp4","item2":"/video2.mp4","item3":"/video3.mp4"}]'),
((SELECT id FROM programs WHERE slug = 'naan-mudhalvan-2024'), 'conclusion', 'Conclusion', 'The collaboration between Rareminds and TNSDC''s Naan Mudhalvan program stands as a model for impactful public–private partnerships in higher education. By turning traditional classrooms into hubs of innovation and applied learning, Rareminds empowered thousands of students to transition from passive learners to confident, industry-ready contributors across agriculture, food technology, and EV sectors. This partnership demonstrates how purposeful education reform can drive future-ready outcomes at scale.')
ON CONFLICT (program_id, section_key) DO NOTHING;
-- Insert program sections for Naan Mudhalvan 2023
INSERT INTO program_sections (program_id, section_key, title, content) VALUES
((SELECT id FROM programs WHERE slug = 'naan-mudhalvan-2023'), 'introduction', 'Introduction', 'Rareminds proudly partnered with the Tamil Nadu Skill Development Corporation (TNSDC) under the Naan Mudhalvan flagship program to significantly enhance the technical education landscape for Arts and Science students across Tamil Nadu. This initiative focused on delivering high-impact, project-based training in critical emerging technologies, effectively bridging traditional classroom learning with practical, real-world applications. The collaboration equipped students with future-ready skills and the confidence essential for success in the evolving digital and industrial workforce.'),
((SELECT id FROM programs WHERE slug = 'naan-mudhalvan-2023'), 'about', 'About the Program', 'As part of this strategic collaboration, Rareminds delivered four specialized 45-hour experiential training programs to undergraduate students during the Even Semester of the 2023–2024 academic year. These mandatory courses were designed to provide hands-on experience and practical understanding in key sectors: Agribusiness Management, EV Battery Management, Food Analysis, Organic Food Production Techniques. Each program combined theoretical knowledge with practical application, enabling students to engage in comprehensive projects, simulations, and real-world problem-solving from day one. The curriculum included physical classroom interventions and supplementary LMS-based content, ensuring a dynamic and blended learning experience.'),
((SELECT id FROM programs WHERE slug = 'naan-mudhalvan-2023'), 'course_enrollment', 'Detailed Course Enrollment by University', 'Agribusiness Management - Total: 2,072 students across Alagappa University (296), Bharathidasan University (963), Madurai Kamaraj University (223), Mother Teresa University (93), Manonmaniam Sundaranar University (497).EV Battery Management - Total: 14,564 students across multiple universities including Periyar University (3,653), Thiruvalluvar University (2,541), Bharathidasan University (1,749), Annamalai University (1,651), University of Madras (1,472), Manonmaniam Sundaranar University (953), Bharathiar University (879), Madurai Kamaraj University (789), Alagappa University (632), Mother Teresa University (245). Food Analysis - Total: 1,637 students across Thiruvalluvar University (813), University of Madras (824).Organic Food Production Techniques - Total: 2,044 students across Periyar University (1,282), Annamalai University (541), Bharathiar University (221).'),
((SELECT id FROM programs WHERE slug = 'naan-mudhalvan-2023'), 'impact', 'Key Outcomes & Impact', '20,317 students trained through structured, mentor-led sessions across various universities in Tamil Nadu. 100% of participants completed comprehensive final projects, demonstrating practical application of their learning Evaluations were conducted jointly by college faculty and Rareminds'' industry experts. High engagement in mandatory hackathons, wherever applicable, fostering innovation, critical thinking, and collaborative problem-solving. Strengthened employability outcomes, with integrated placement, internship, and hackathon support initiatives. Positive institutional feedback from TNSDC and partner universities, highlighting increased student engagement, curiosity, and application-based learning.'),
((SELECT id FROM programs WHERE slug = 'naan-mudhalvan-2023'), 'strategic_alignment', 'Strategic Alignment with TNSDC Goals', 'Skill Development & Employability: Delivery of industry-aligned content boosted the job-readiness of Arts and Science graduates.

Curriculum Innovation: Introduction of emerging technology domains aligned academic offerings with evolving industry needs.

Student Engagement & Retention: Project-based learning significantly increased student interest, satisfaction, and knowledge retention.

Workforce Readiness: The program nurtured a talent pipeline in sectors critical to Tamil Nadu socio-economic development.'),
((SELECT id FROM programs WHERE slug = 'naan-mudhalvan-2023'), 'video', 'Program Videos', '[{"item1":"/video1.mp4","item2":"/video2.mp4","item3":"/video3.mp4"}]'),
((SELECT id FROM programs WHERE slug = 'naan-mudhalvan-2023'), 'conclusion', 'Conclusion', 'The successful collaboration between Rareminds and the TNSDC''s Naan Mudhalvan program demonstrated Rareminds'' proven capacity to deliver measurable impact, reimagine classroom learning, and align with both institutional and governmental priorities. By turning classrooms into active innovation spaces, Rareminds empowered thousands of students to transition from passive learners to confident contributors in the fields of technology, agriculture, and sustainability. This initiative remains a shining example of how public-private partnerships can reshape education for a future-ready India.')
ON CONFLICT (program_id, section_key) DO NOTHING;

-- Insert program sections for Naan Mudhalvan 4th sem 2025
INSERT INTO program_sections (program_id, section_key, title, content) VALUES
((SELECT id FROM programs WHERE slug = 'naan-mudhalvan-4th-sem-2025'), 'introduction', 'Introduction', 'Rareminds partnered with the Tamil Nadu Skill Development Corporation (TNSDC) under the "Naan Mudhalvan" flagship initiative to transform technical education for Arts and Science students across Tamil Nadu. The program delivered high-impact, project-based training in emerging technologies, effectively bridging classroom theory with real-world application. It empowered students with future-ready skills, practical exposure, and the confidence to meet evolving industry demands.'),
((SELECT id FROM programs WHERE slug = 'naan-mudhalvan-4th-sem-2025'), 'about', 'About the Program', '
 Rareminds delivered specialized 45-hour experiential training programs to undergraduate students during the 4th Semester of the 2024–2025 academic year. These mandatory programs offered immersive, hands-on learning in the following domains: Food Analysis, Processing and Preservation Techniques, Organic Food Production Techniques, Sustainability & Green Chemistry in EV Sector, Chemical Safety in Battery Management. The programs combined in-person instruction with LMS-based support, enabling students to engage in real-time simulations, projects, and practical applications from day one.'),
((SELECT id FROM programs WHERE slug = 'naan-mudhalvan-4th-sem-2025'), 'course_enrollment', 'Detailed Course Enrollment by University', '1. Food Analysis, Processing and Preservation Techniques (4th Semester) - Total: 5,219 students across Periyar University (1,351), University of Madras (850), Thiruvalluvar University (929), Annamalai University (565), Manonmaniam Sundaranar University (555), Bharathiar University (323), Alagappa University (301), Madurai Kamaraj University (224), Mother Teresa University (121). 2. Organic Food Production Techniques (4th Semester) - Total: 991 students across Bharathidasan University (991). 3. Sustainability & Green Chemistry in EV Sector (4th Semester) - Total: 7,483 students across Bharathidasan University (1,693), Annamalai University (1,648), Thiruvalluvar University (1,550), Madurai Kamaraj University (878), Manonmaniam Sundaranar University (968), Alagappa University (516), Mother Teresa University (230). 4. Chemical Safety in Battery Management (4th Semester) - Total: 2,755 students across Alagappa University (572), Madurai Kamaraj University (893), Manonmaniam Sundaranar University (1,044), Mother Teresa University (246).'),
((SELECT id FROM programs WHERE slug = 'naan-mudhalvan-4th-sem-2025'), 'impact', 'Key Outcomes & Impact', '2,755 students trained on Chemical Safety in Battery Management Strong hands-on learning outcomes through mentor-led sessions and real-world applications. 100% project completion across all enrolled students, evaluated jointly by Master Assessor Faculty and Rareminds'' industry experts. 70%+ student participation in mandatory hackathons promotes innovation, collaboration, and problem-solving. Enhanced employability through post-training support, including placement drives and internship opportunities, targeting at least 25% placement conversion. Positive feedback from TNSDC and universities citing better engagement, curiosity, and practical understanding among students Large-scale implementation across leading universities.'),
((SELECT id FROM programs WHERE slug = 'naan-mudhalvan-4th-sem-2025'), 'strategic_alignment', 'Strategic Alignment with TNSDC Goals', 'Skill Development & Employability: Delivered industry-relevant, practical skills.

Curriculum Innovation: Introduced cutting-edge, policy-aligned programs.

Student Engagement: Strengthened participation through experiential learning.

Workforce Readiness: Built a pipeline of skilled graduates.'),
((SELECT id FROM programs WHERE slug = 'naan-mudhalvan-4th-sem-2025'), 'video', 'Program Videos', '[{"item1":"/video1.mp4","item2":"/video2.mp4","item3":"/video3.mp4"}]'),
((SELECT id FROM programs WHERE slug = 'naan-mudhalvan-4th-sem-2025'), 'conclusion', 'Conclusion', 'The Rareminds–TNSDC collaboration under the Naan Mudhalvan initiative demonstrates strong industry-academia synergy. By combining innovation, hands-on learning, and outcome-driven delivery, Rareminds enabled thousands of students to transition into confident, future-ready professionals.')
ON CONFLICT (program_id, section_key) DO NOTHING;
