-- Insert program sections for Naan Mudhalvan 2025
INSERT INTO program_sections (program_id, section_key, title, content) VALUES
((SELECT id FROM programs WHERE slug = 'naan-mudhalvan-2025'), 'introduction', 'Introduction', 'Rareminds proudly partnered with the Tamil Nadu Skill Development Corporation (TNSDC) under the "Naan Mudhalvan" flagship initiative to transform technical education for Arts and Science students across Tamil Nadu. This program focused on delivering high-impact, project-based training in critical emerging technologies—bridging classroom theory with real-world practice. The partnership empowered students with future-ready skills, practical exposure, and the confidence to meet the demands of an evolving digital and industrial workforce.'),
((SELECT id FROM programs WHERE slug = 'naan-mudhalvan-2025'), 'about', 'About the Program', 'Through this collaboration, Rareminds delivered five specialized 45-hour experiential training programs to undergraduate students during the Odd Semester (5th) of the 2025–2026 academic year. These mandatory programs provided immersive, hands-on learning experiences in the following sectors: Good Manufacturing Practices, Medical Coding, Food Safety and Quality Management. The courses blended in-person classes with LMS-based support, enabling students to work on real-time simulations, projects, and practical applications from day one.'),
((SELECT id FROM programs WHERE slug = 'naan-mudhalvan-2025'), 'course_enrollment', 'Detailed Course Enrollment by University', '1. Medical Coding (5th Semester) - Total: 3,886 students across Periyar University (2,987), Bharathiar University (899). 2. GMP (5th Semester) - Total: 5,049 students across Periyar University (2,148), Manonmaniam Sundaranar University (949), Madurai Kamaraj University (797), Alagappa University (508), Bharathiar University (420), Mother Teresa University (227). 3. Food Safety and Quality Management (5th Semester) - Total: 5,560 students across Periyar University (1,283), Thiruvalluvar University (888), Bharathidasan University (868), Annamalai University (556), University of Madras (557), Manonmaniam Sundaranar University (540), Bharathiar University (301), Alagappa University (292), Madurai Kamaraj University (157), Mother Teresa University (118).'),
((SELECT id FROM programs WHERE slug = 'naan-mudhalvan-2025'), 'impact', 'Objectives', '14,495 students to be trained through hands-on, mentor-led sessions across major Tamil Nadu universities. 100% project completion across all enrolled students, evaluated jointly by Master Assessor Faculty and Rareminds'' industry experts. 70%+ student participation in mandatory hackathons promotes innovation, collaboration, and problem-solving. Enhanced employability through post-training support, including placement drives and internship opportunities, targeting at least 25% placement conversion. Positive feedback from TNSDC and universities citing better engagement, curiosity, and practical understanding among students.'),
((SELECT id FROM programs WHERE slug = 'naan-mudhalvan-2025'), 'strategic_alignment', 'Strategic Alignment with TNSDC Goals', 'Skill Development & Employability: Provide students with industry-relevant, practical skills.

Curriculum Innovation: Introduce cutting-edge topics aligned with national education policy.

Student Engagement: Elevate learning interest through experiential pedagogy.

Workforce Readiness: Create a pipeline of skilled graduates prepared for high-demand industries.'),
((SELECT id FROM programs WHERE slug = 'naan-mudhalvan-2025'), 'video', 'Program Videos', '[{"item1":"/video1.mp4","item2":"/video2.mp4","item3":"/video3.mp4"}]'),
((SELECT id FROM programs WHERE slug = 'naan-mudhalvan-2025'), 'conclusion', 'Conclusion', 'The Rareminds–TNSDC collaboration under the Naan Mudhalvan initiative exemplifies impactful industry-academia synergy. By integrating innovation, hands-on learning, and outcome-driven models, Rareminds helped thousands of students transition from passive learners to future-ready professionals. This program stands as a scalable model for education transformation and skill empowerment across India.')
