-- Insert program sections for Tripura
INSERT INTO program_sections (program_id, section_key, title, content) VALUES
((SELECT id FROM programs WHERE slug = 'tripura'), 'introduction', 'Equipping Candidates for Global Careers with Confidence & Clarity', 'Overseas job interviews demand more than just qualifications — they require candidates to present themselves with poise, adapt to cross-cultural environments, and navigate high-stakes conversations effectively. Tripura Skill Development Corporation (TSDC) identified the need to prepare aspiring overseas placement candidates with focused, practical training that would address both interview performance and communication competency. A targeted approach was implemented to ensure that participants — ranging from ITI graduates to young professionals — received actionable strategies, hands-on practice, and cross-cultural readiness for international job markets. Rareminds, under the leadership of CEO Dr. Subhashini, delivered a structured 10-hour training program designed to build both competence and confidence. Dr. Subhashini personally conducted the sessions, bringing strategic insights and real-world experience directly to participants.'),
((SELECT id FROM programs WHERE slug = 'tripura'), 'programs', 'Program Delivery', 'Total Training Hours: 10 hours. Schedule: 2 hours/day across 5 days. Participants Trained: 200 candidates (Two batches of 100 each). Participant Profile: ITI, Diploma, Graduates, Postgraduates, Young Professionals. Trainer: Dr. Subhashini, CEO, Rareminds.'),
((SELECT id FROM programs WHERE slug = 'tripura'), 'modules', 'Modules Covered', 'Interview Skills: Effective Resume and Cover Letter Writing, Common Interview Questions & Best Practices, Non-verbal Communication & Body Language, Handling Difficult Questions & Stress Management, Mock Interviews with Personalized Feedback. Cross-cultural Communication: Understanding Cultural Differences and Sensitivities, Communication Strategies for Diverse Audiences, Global Business Etiquette, Intercultural Conflict Resolution & Negotiation.'),
((SELECT id FROM programs WHERE slug = 'tripura'), 'approaches', 'Multiple Approaches', 'Interactive Presentations & Case Studies. Group Discussions & Peer Activities. Roleplays & Interview Simulations. Individualized Coaching & Feedback.'),
((SELECT id FROM programs WHERE slug = 'tripura'), 'impact', 'Outcomes and Impact', '95% participants reported improved confidence in handling interviews. 92% demonstrated better articulation in mock interview evaluations. 87% showed improvement in cross-cultural awareness and etiquette. 100% of participants completed mock interviews with personalized feedback. Post-training self-assessment scores improved by an average of 40% across key skill areas. Participant feedback emphasized high satisfaction with the hands-on approach, real-world relevance, and the opportunity to practice in simulated interview environments.'),
((SELECT id FROM programs WHERE slug = 'tripura'), 'strategic_alignment', 'Strategic Alignment with TSDC Goals', 'This initiative directly supported TSDC''s mission to strengthen global employability for regional youth, bridge skill gaps through targeted communication and interview training, prepare candidates for diverse cultural and professional environments, and enhance placement success rates through practical readiness.'),
((SELECT id FROM programs WHERE slug = 'tripura'), 'video', 'Program Videos', '[{"item1":"/video1.mp4","item2":"/video2.mp4","item3":"/video3.mp4"}]'),
((SELECT id FROM programs WHERE slug = 'tripura'), 'conclusion', 'Turning Aspirants into Global Professionals', 'Through this focused intervention, Rareminds — under the direct leadership and facilitation of CEO Dr. Subhashini — empowered Tripura''s overseas placement aspirants with the tools, confidence, and global readiness essential for success. The program served not only as a skill-building platform but also as a mindset transformation, directly contributing to TSDC''s vision of creating globally competitive talent.')
ON CONFLICT (program_id, section_key) DO NOTHING;
-- Insert program sections for TNSDC ITI (Spoken English)
INSERT INTO program_sections (program_id, section_key, title, content) VALUES
((SELECT id FROM programs WHERE slug = 'tnsdc-iti-spoken-english'), 'introduction', 'Introduction', 'Rareminds partnered with Tamil Nadu Skill Development Corporation (TNSDC) to improve English and personality development among students in government welfare hostels. This was hands-on training that equipped students with critical communication skills and confidence for their future academic and professional life.'),
((SELECT id FROM programs WHERE slug = 'tnsdc-iti-spoken-english'), 'about', 'About the Program', 'English & Personality Development: A full English and Personality Development program was offered to 2nd and 3rd year students in Tribal, ADW, BC, MBC, DNC, and Minorities Welfare Department Hostels.

Learning & Assessment: The curriculum used open-source documentary movies for listening/speaking practice, English newspapers for reading/writing, and dedicated workbooks for structured assessments. Cambridge University administered pre- and post-training exams to monitor student progress and track improvement on the CEFR scale.'),
((SELECT id FROM programs WHERE slug = 'tnsdc-iti-spoken-english'), 'impact', 'Key Outcomes & Impact', 'Trained 10,210 students over 7 Months on English communication and personal development skills. The program was offered in 7 districts of Tamil Nadu (Nammakkal, Coimbatore, Tiruppur, Nilgiris, Erode, Salem, and Karur) in 90+ hostels. The program was delivered by 150+ trainers. Core Competencies: Students improved their basic English, conversational skills, and reading comprehension. Cambridge assessments are at the heart of Rareminds'' outcome-driven approach, which is about measurable improvement (at least one CEFR level up) The following are the grades as assessed by Cambridge. 52.14% of students achieved A2, indicating strong foundational English proficiency post-training. 6.84% of students reached B1, showing above-basic competence and readiness for workplace communication. 6.84% of students remained at A1, suggesting emerging skills that need continued support. 0.85% improved from A1 to A2, demonstrating upward growth. 0.85% progressed from A2 to B1, showing measurable advancement.'),
((SELECT id FROM programs WHERE slug = 'tnsdc-iti-spoken-english'), 'strategic_alignment', 'Strategic Alignment with TNSDC & Government Goals', 'The initiative supported TNSDC and the Government of Tamil Nadu''s key objectives: Empowering underprivileged students by training life and communication skills in Tribal, ADW, BC, MBC, DNC, and Minority welfare hostels. Better job prospects and social integration by building students'' confidence and communication skills, which will lead to better future opportunities. Cambridge University Press ensures accountability and quality assurance through independent standardized assessments to measure learning outcomes. Practical English for daily use and future opportunities, not just academic proficiency.'),
((SELECT id FROM programs WHERE slug = 'tnsdc-iti-spoken-english'), 'video', 'Program Videos', '[{"item1":"/video1.mp4","item2":"/video2.mp4","item3":"/video3.mp4"}]'),
((SELECT id FROM programs WHERE slug = 'tnsdc-iti-spoken-english'), 'conclusion', 'Building Lasting Confidence', 'Rareminds delivers measurable impact in English communication and personality development across diverse learner groups. By aligning with the government''s student empowerment goals, Rareminds focuses on practical, confidence-building interventions grounded in the CEFR framework, ensuring structured and outcome-driven progress. While rote learning has its place in foundational skill-building, Rareminds integrates it with real-world communication strategies to foster both accuracy and fluency. Students gain the ability to apply language meaningfully—in interviews, group settings, and digital communication. The program is adaptable, culturally relevant, and designed to support lifelong language confidence across regions and learner levels.')
ON CONFLICT (program_id, section_key) DO NOTHING;

-- Insert program sections for TNSDC Schools
INSERT INTO program_sections (program_id, section_key, title, content) VALUES

((SELECT id FROM programs WHERE slug = 'tnsdc-schools'), 
'introduction', 
'Introduction', 
'Rareminds, in a significant partnership with the Tamil Nadu Skill Development Corporation, recently concluded a transformative 7-day (45-hour) vocational training program across 121 Government Higher Secondary Schools (GHSS). This initiative was designed to empower 12th-grade (2nd PUC) students with tangible, in-demand skills, paving the way for entrepreneurship and enhancing employability in key growth sectors.'),

((SELECT id FROM programs WHERE slug = 'tnsdc-schools'), 
'about', 
'About the Program', 
'The program successfully reached 1,974 students students allocated by the Tamil Nadu Skill Development Corporation, demonstrating Rareminds'' expertise in large-scale, impactful educational delivery. The 7-day engagement offered students two distinct, yet equally valuable, vocational pathways: Cloud Kitchen Operations: Encouraging the Entrepreneur This stream was designed to give students a comprehensive understanding of the burgeoning cloud kitchen industry, equipping them with the knowledge to launch and manage their food ventures. Agri-Food Processing & Preservation: Cultivating Skills and Opportunities This comprehensive 40-hour curriculum equips students with vital knowledge of the agri-food industry, focusing on practical ways to enhance food value, improve safety standards, and extend shelf life.'),

((SELECT id FROM programs WHERE slug = 'tnsdc-schools'), 
'impact', 
'Key Outcomes & Impact', 
'The program was implemented across 121 Government Higher Secondary Schools (GHSS). 1,974 students were successfully trained. Five Villupuram schools successfully implemented the Cloud Kitchen entrepreneurship program, training 76 aspiring food entrepreneurs. The Agri-Food Processing & Preservation program was implemented in 116 schools, where 1,570 students gained practical skills and knowledge and started their home business. Students gained hands-on experience through activities such as canning, bottling, pickling, fermentation, drying, and freezing techniques. Students were introduced to food safety principles, hygiene practices, HACCP basics, and quality control measures. Students who started business registered under FSSAI.'),

((SELECT id FROM programs WHERE slug = 'tnsdc-schools'), 
'strategic_alignment', 
'Strategic Alignment with TNSDC Goals', 
'This initiative supported key institutional objectives such as: Effortless Enterpreneurship alignment through skill-based, experiential learning integration. Enhanced student employability with practical, in-demand skills and entrepreneurship training. Future-proof curriculum in high-growth sectors like food technology and entrepreneurship. Proven government partnership ensuring reliable implementation of large-scale programs. Fully integrated program delivery reducing administrative burden for institutions. Measurable impact through structured reporting and feedback on student skills and confidence.'),
  
((SELECT id FROM programs WHERE slug = 'tnsdc-schools'), 'video', 'Program Videos', '[{"item1":"/video1.mp4","item2":"/video2.mp4","item3":"/video3.mp4"}]'),

((SELECT id FROM programs WHERE slug = 'tnsdc-schools'), 
'conclusion', 
'Conclusion', 
'This successful GHSS project underscores Rareminds'' dedication to delivering high-quality, large-scale vocational training in collaboration with government bodies. By empowering nearly 2,000 students with practical knowledge and entrepreneurial insights, we are actively shaping a more skilled, confident, and future-ready generation.')
ON CONFLICT (program_id, section_key) DO NOTHING;

