-- Insert program sections for Global International School
INSERT INTO program_sections (program_id, section_key, title, content) VALUES
((SELECT id FROM programs WHERE slug = 'global-international-school'), 'introduction', 'Global International School – Empowering Teachers', 'From Content Delivery to Classroom Impact in 2 Days. Teachers shape the learning environment, but they can only transform classrooms when they are equipped and inspired. However, most lacked structured exposure to NEP-aligned pedagogy, meaningful technology integration, and effective strategies to manage young, modern learners. The shift from traditional instruction to learner-centric approaches demanded more than content knowledge. It required mindset shifts, new tools, and practical strategies. Yet, most training programs remained too theoretical or generic to create lasting change. Rareminds was invited to bridge this critical gap with focused, hands-on capacity-building for today''s classrooms.'),
((SELECT id FROM programs WHERE slug = 'global-international-school'), 'inventions', 'Rareminds Intervention', 'In November 2023, Rareminds conducted a 2-day intensive capacity-building program for 40 teachers at Global International School. Led by 3 expert master trainers, the sessions blended foundational understanding with practical application.'),
((SELECT id FROM programs WHERE slug = 'global-international-school'), 'modules', 'Modules Covered', 'Contemporary Education and Classroom Skills. Digital Tools for Teaching. Creating a Feedback Culture. Student Engagement Based on Learner Profiles. Activity-Based Teaching Modules. Personalized Reflection and Action Planning.'),
((SELECT id FROM programs WHERE slug = 'global-international-school'), 'approaches', 'Multiple Approaches', 'Interactive Group Activities and Demos. Peer Discussions and Application Circles. Micro-Innovation Planning for Classroom Practice.'),
((SELECT id FROM programs WHERE slug = 'global-international-school'), 'impact', 'Outcomes and Impact', '100% participation and engagement across all sessions. Teachers developed classroom innovation plans post-training. Improved lesson planning confidence and use of engagement tools.'),
((SELECT id FROM programs WHERE slug = 'global-international-school'), 'strategic_alignment', 'Strategic Alignment with Global International School Goals', 'This initiative directly supported the school''s goals around: Teacher Capacity Building and NEP Integration. Rapid Upskilling with Practical Teaching Tools. Personalized Classroom Innovation Initiatives. Enhanced Student Engagement and Retention.'),
((SELECT id FROM programs WHERE slug = 'global-international-school'), 'video', 'Program Videos', '[{"item1":"/video1.mp4","item2":"/video2.mp4","item3":"/video3.mp4"}]'),
((SELECT id FROM programs WHERE slug = 'global-international-school'), 'conclusion', 'Conclusion: Turning Educators into Enablers', 'At Global International School, Rareminds supported teachers to go beyond delivery. By equipping them with modern strategies, tech tools, and learner-focused frameworks, we helped lay the groundwork for classrooms that are engaging, inclusive, and impact-driven. It was more than training—it was a catalyst for everyday transformation.')
ON CONFLICT (program_id, section_key) DO NOTHING;

